-- YAMA AI Legal Database Export
-- Generated: 2026-03-15T18:11:33.521733
-- Records: 87

CREATE TABLE IF NOT EXISTS law_sections (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    act_name VARCHAR(500) NOT NULL,
    section_number VARCHAR(50) NOT NULL,
    title VARCHAR(1000) NOT NULL,
    description TEXT NOT NULL,
    keywords TEXT,
    category VARCHAR(100) NOT NULL DEFAULT 'general',
    punishment TEXT,
    old_law_reference VARCHAR(500),
    jurisdiction VARCHAR(50) DEFAULT 'central',
    state_name VARCHAR(200),
    law_type VARCHAR(100) DEFAULT 'act',
    source_url VARCHAR(2000),
    content_hash VARCHAR(64),
    is_active BOOLEAN DEFAULT 1,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP
);

